INSERT INTO passage_questions (id, passage_id, question_number, question_type, question_text, explanation, correct_choice) VALUES
(235, 79, 1, 'comprehension', 'According to the passage, why does a decline in carbonate ion concentration threaten marine organisms?', '第2段落で、炭酸イオンはサンゴや軟体動物などが殻や骨格を構築する石灰化プロセスに不可欠であると説明されている。炭酸塩が減少すると保護外殻の構築・維持が困難になり、捕食や病気に脆弱になる。選択肢1がこの説明に最も合致する。', 1),
(236, 79, 2, 'comprehension', 'What does the passage indicate about current efforts to address ocean acidification?', '第5段落で、緩和の取り組みは「sporadic and insufficient」（散発的で不十分）であり、アルカリ性鉱物の展開や海草栽培などの提案も「rudimentary stages of development」（発達の初期段階）にあると述べられている。根本的解決は化石燃料消費の削減だが、国際交渉では「contentious」（論議を呼ぶ）とされている。選択肢3がこの状況を最も正確に反映している。', 3),
(237, 79, 3, 'fill_in_blank', 'Choose the best option to fill in the blank [BLANK] in the passage.', '空所は第4段落にあり、翼足類の殻の溶解という発見の意味合いが入る。直後の文で翼足類の個体数崩壊が海洋生態系全体に影響を及ぼし、漁業を弱体化させると述べられている。選択肢4「alarmed researchers who had previously assumed that acidification''s effects would not manifest so rapidly or so visibly」（酸性化の影響がこれほど急速にまたは目に見える形で現れるとは思っていなかった研究者たちを驚愕させた）が文脈に最も合致する。', 4);
INSERT INTO question_choices (question_id, choice_number, choice_text) VALUES
(235, 1, 'Carbonate ions are essential for calcification, the process by which corals and mollusks build their shells and skeletal structures.'),
(235, 2, 'Carbonate ions regulate the temperature of ocean currents, and their loss causes waters to become fatally cold for marine life.'),
(235, 3, 'Carbonate ions provide the primary nutrient source for phytoplankton, which form the base of the marine food chain.'),
(235, 4, 'Carbonate ions prevent the formation of harmful algal blooms that deplete oxygen in coastal waters.'),
(236, 1, 'International agreements have successfully mandated binding reductions in oceanic carbon dioxide levels.'),
(236, 2, 'The deployment of alkaline minerals has already reversed acidification in several major reef systems.'),
(236, 3, 'While some interventions have been proposed, they remain in early development, and the fundamental solution of reducing emissions is politically difficult to achieve.'),
(236, 4, 'Scientists have abandoned research into localized solutions and are focusing exclusively on atmospheric carbon capture.'),
(237, 1, 'confirmed that pteropods can regenerate their shells within a single breeding season if conditions improve'),
(237, 2, 'suggested that the Southern Ocean remains the only body of water where acidification has reached critical levels'),
(237, 3, 'proved that ocean acidification is a natural cyclical phenomenon unrelated to human carbon emissions'),
(237, 4, 'alarmed researchers who had previously assumed that acidification''s effects would not manifest so rapidly or so visibly');
